export type ActionType = 
  | 'ADD_CUSTOMER' 
  | 'GET_BALANCE' 
  | 'ADD_PAYMENT' 
  | 'CREATE_INVOICE' 
  | 'LOOKUP_CUSTOMER' 
  | 'ANALYZE_DAILY_TRANSACTIONS'
  | 'UNKNOWN';

export interface CrmAction {
