import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { CrmAction, ActionType } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const SYSTEM_INSTRUCTION = `
You are Sudarshan CRM Assistant, a friendly Hindi-English assistant for Indian MSMEs.
Your role is to understand messages in Hindi, English, or Hinglish and convert them into structured JSON actions.

Core Action Protocols:
- ADD_CUSTOMER: { business_name, owner_name, phone }
- GET_BALANCE: { customer_name }
- ADD_PAYMENT: { customer_name, amount, payment_mode }
- CREATE_INVOICE: { customer_name, amount, items }
- LOOKUP_CUSTOMER: { phone_or_name }

Always return valid JSON. No extra text.
Tone: Polite, business-friendly, mixed Hindi-English (Hinglish).
`;

const DIARY_ANALYSIS_INSTRUCTION = `
Carefully analyze the handwritten diary image. 
Identify entries for:
- SALE (bikri, aamdani, sales)
- PURCHASE (kharid, stock, maal liya)
- EXPENSE (kharcha, rent, chai, light bill)

Extract:
- type: "SALE", "PURCHASE", or "EXPENSE"
- label: Short description in Hinglish
- amount: Number (Rupees)

Calculate:
- total_sale
- total_purchase
- total_expense
- profit_loss = total_sale - (total_purchase + total_expense)

Generate:
- summary_hindi: A short 2-4 line summary in simple Hindi.
- action_steps_hindi: Exactly 5 simple action points in Hindi for the shopkeeper.

Output Schema:
{
  "action": "ANALYZE_DAILY_TRANSACTIONS",
  "parameters": {
    "transactions": [{ "type": string, "label": string, "amount": number }],
    "total_sale": number,
    "total_purchase": number,
    "total_expense": number,
    "profit_loss": number
  },
  "insights": {
    "summary_hindi": string,
    "action_steps_hindi": string[]
  },
  "reply": string
}
`;

export async function processChat(message: string): Promise<CrmAction> {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: message,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            action: { type: Type.STRING },
            parameters: { type: Type.OBJECT },
            reply: { type: Type.STRING }
          },
          required: ["action", "parameters", "reply"]
        }
      }
    });

    const result = JSON.parse(response.text || '{}');
    return result as CrmAction;
  } catch (error) {
    console.error("Gemini Chat Error:", error);
    return {
      action: 'UNKNOWN' as ActionType,
      parameters: {},
      reply: "Maaf kijiye, main samajh nahi paaya. Kya aap fir se bol sakte hain?"
    };
  }
}

export async function analyzeDiaryImage(base64Image: string): Promise<CrmAction> {
  try {
    const imagePart = {
      inlineData: {
        mimeType: 'image/jpeg',
        data: base64Image,
      },
    };

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { 
        parts: [
          imagePart, 
          { text: "Analyze this handwritten daily ledger image and extract transactions as JSON. Suggest 5 improvements in Hindi." }
        ] 
      },
      config: {
        systemInstruction: DIARY_ANALYSIS_INSTRUCTION,
        responseMimeType: "application/json"
      }
    });

    const result = JSON.parse(response.text || '{}');
    return result as CrmAction;
  } catch (error) {
    console.error("Gemini Vision Error:", error);
    throw error;
  }
}

