import React, { useState, useRef } from 'react';
import { analyzeDiaryImage } from '../services/gemini';
import { CrmAction, Transaction } from '../types';

const DiaryAnalyzer: React.FC = () => {
  const [image, setImage] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<CrmAction | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setImage(reader.result as string);
        setResult(null);
      };
      reader.readAsDataURL(file);
    }
  };

  const startAnalysis = async () => {
    if (!image) return;
    setLoading(true);
    try {
      const base64Data = image.split(',')[1];
      const analysisResult = await analyzeDiaryImage(base64Data);
      setResult(analysisResult);
    } catch (error) {
      alert("Analysis fail ho gayi. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  const getTransactionColor = (type: string) => {
    switch(type) {
      case 'SALE': return 'text-green-600';
      case 'PURCHASE': return 'text-orange-600';
      case 'EXPENSE': return 'text-red-600';
      default: return 'text-gray-600';
    }
  };

  return (
    <div className="p-4 space-y-6 pb-24">
      <div className="flex justify-between items-center">
        <h1 className="text-2xl font-bold text-gray-800">Diary Analysis</h1>
        <button 
          onClick={() => fileInputRef.current?.click()}
          className="p-2 rounded-full bg-indigo-50 text-indigo-600"
        >
          <i className="fas fa-camera text-xl"></i>
        </button>
      </div>

      <input 
        type="file" 
        accept="image/*" 
        capture="environment"
        className="hidden" 
        ref={fileInputRef} 
        onChange={handleImageUpload}
      />

      {!image && (
        <div 
          onClick={() => fileInputRef.current?.click()}
          className="border-2 border-dashed border-gray-300 rounded-3xl p-12 text-center space-y-4 cursor-pointer hover:border-indigo-400 transition-colors"
        >
          <div className="w-16 h-16 bg-indigo-50 rounded-full flex items-center justify-center mx-auto text-indigo-400">
            <i className="fas fa-image text-3xl"></i>
          </div>
          <div>
            <p className="font-bold text-gray-700">Upload Diary Photo</p>
            <p className="text-sm text-gray-400">Take a photo of your handwritten hisaab</p>
          </div>
        </div>
      )}

      {image && !result && (
        <div className="space-y-4">
          <div className="rounded-2xl overflow-hidden shadow-md border-4 border-white">
            <img src={image} alt="Diary Preview" className="w-full h-auto" />
          </div>
          <button 
            onClick={startAnalysis}
            disabled={loading}
            className="w-full bg-indigo-600 text-white font-bold py-4 rounded-2xl shadow-lg active:scale-95 transition-all flex items-center justify-center gap-3 disabled:bg-gray-400"
          >
            {loading ? (
              <>
                <i className="fas fa-spinner fa-spin"></i>
                Processing Hisaab...
              </>
            ) : (
              <>
                <i className="fas fa-magic"></i>
                Read This Page
              </>
            )}
          </button>
        </div>
      )}

      {result && (
        <div className="animate-in fade-in slide-in-from-bottom-4 duration-500 space-y-6">
          <div className="bg-white p-5 rounded-2xl shadow-sm border border-gray-100">
            <h3 className="font-bold text-indigo-700 mb-3 border-b pb-2 flex items-center gap-2">
              <i className="fas fa-chart-line"></i>
              Aaj ka Summary
            </h3>
            <p className="text-gray-700 leading-relaxed mb-4">
              {result.insights?.summary_hindi || result.reply}
            </p>

            <div className="grid grid-cols-2 gap-4">
              <div className="bg-green-50 p-3 rounded-xl">
                <p className="text-xs text-green-600 font-bold uppercase">Total Sale</p>
                <p className="text-xl font-black text-green-700">₹{result.parameters.total_sale}</p>
              </div>
              <div className="bg-red-50 p-3 rounded-xl">
                <p className="text-xs text-red-600 font-bold uppercase">Today's Profit</p>
                <p className="text-xl font-black text-red-700">₹{result.parameters.profit_loss}</p>
              </div>
            </div>
          </div>

          <div className="bg-white p-5 rounded-2xl shadow-sm border border-gray-100">
            <h3 className="font-bold text-amber-700 mb-4 flex items-center gap-2">
              <i className="fas fa-lightbulb"></i>
              Success Tips (Kal ke liye)
            </h3>
            <ul className="space-y-3">
              {result.insights?.action_steps_hindi.map((step, i) => (
                <li key={i} className="text-sm text-gray-700 bg-amber-50 p-3 rounded-lg border-l-4 border-amber-400 italic">
                  {step}
                </li>
              ))}
            </ul>
          </div>

          <div className="bg-white p-5 rounded-2xl shadow-sm border border-gray-100">
            <h3 className="font-bold text-gray-700 mb-4">Entry Details</h3>
            <div className="space-y-3">
              {result.parameters.transactions.map((t: Transaction, i: number) => (
                <div key={i} className="flex justify-between items-center py-2 border-b border-gray-50 last:border-0">
                  <div>
                    <p className="text-sm font-bold text-gray-800">{t.label}</p>
                    <p className="text-[10px] text-gray-400 font-bold tracking-widest uppercase">{t.type}</p>
                  </div>
                  <p className={`font-bold ${getTransactionColor(t.type)}`}>
                    {t.type === 'SALE' ? '+' : '-'}₹{t.amount}
                  </p>
                </div>
              ))}
            </div>
          </div>

          <button 
            onClick={() => { setImage(null); setResult(null); }}
            className="w-full text-indigo-600 font-bold py-3 border-2 border-indigo-100 rounded-2xl"
          >
            Naya Page Analyze Karein
          </button>
        </div>
      )}
    </div>
  );
};

export default DiaryAnalyzer;

import React, { useState } from 'react';
import { processChat } from '../services/gemini';
import { CrmAction } from '../types';

const ChatAgent: React.FC = () => {
  const [messages, setMessages] = useState<{ text: string, sender: 'user' | 'bot' }[]>([
    { text: "Namaste! Main Sudarshan Assistant hoon. Main aapki billing aur diary manage karne mein madad kar sakta hoon. Kya kaam hai aaj?", sender: 'bot' }
  ]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);

  const handleSend = async () => {
    if (!input.trim() || loading) return;

    const userMsg = input;
    setMessages(prev => [...prev, { text: userMsg, sender: 'user' }]);
    setInput('');
    setLoading(true);

    try {
      const response: CrmAction = await processChat(userMsg);
      setMessages(prev => [...prev, { text: response.reply, sender: 'bot' }]);

      // If it's a specific action, we might show a UI toast or widget
      if (response.action === 'CREATE_INVOICE') {
        setMessages(prev => [...prev, { text: "Invoice generate ho gaya hai. Aap ise WhatsApp par share kar sakte hain.", sender: 'bot' }]);
      }
    } catch (error) {
      setMessages(prev => [...prev, { text: "Kshama karein, network error hai.", sender: 'bot' }]);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-[calc(100vh-140px)] p-4">
      <div className="flex-1 overflow-y-auto space-y-4 mb-4">
        {messages.map((m, i) => (
          <div key={i} className={`flex ${m.sender === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] p-4 rounded-2xl shadow-sm ${
              m.sender === 'user' 
                ? 'bg-indigo-600 text-white rounded-tr-none' 
                : 'bg-white text-gray-800 rounded-tl-none border border-gray-100'
            }`}>
              <p className="text-sm leading-relaxed">{m.text}</p>
            </div>
          </div>
        ))}
        {loading && (
          <div className="flex justify-start">
            <div className="bg-gray-100 p-3 rounded-2xl rounded-tl-none animate-pulse">
              <p className="text-xs text-gray-400">Thinking...</p>
            </div>
          </div>
        )}
      </div>

      <div className="flex gap-2">
        <input 
          type="text" 
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={(e) => e.key === 'Enter' && handleSend()}
          placeholder="Type in Hindi or English..."
          className="flex-1 bg-white border border-gray-200 rounded-2xl px-4 py-3 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500 shadow-sm"
        />
        <button 
          onClick={handleSend}
          className="bg-indigo-600 text-white w-12 h-12 rounded-2xl flex items-center justify-center shadow-md active:scale-90 transition-transform"
        >
          <i className="fas fa-paper-plane"></i>
        </button>
      </div>
    </div>
  );
};

export default ChatAgent;

