import React, { useState, useRef } from 'react';
import { analyzeDiaryImage, speakHindi } from '../services/gemini';
import { CrmAction, Transaction } from '../types';

const DiaryAnalyzer: React.FC = () => {
  const [image, setImage] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<CrmAction | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setImage(reader.result as string);
        setResult(null);
      };
      reader.readAsDataURL(file);
    }
  };

  const startAnalysis = async () => {
    if (!image) return;
    setLoading(true);
    try {
      const base64Data = image.split(',')[1];
      const analysisResult = await analyzeDiaryImage(base64Data);
      setResult(analysisResult);
      if (analysisResult.insights?.summary_hindi) {
        speakHindi(analysisResult.insights.summary_hindi);
      }
    } catch (error) {
      alert("Analysis fail ho gayi. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  const getTransactionColor = (type: string) => {
    switch(type) {
      case 'SALE': return 'text-emerald-400';
      case 'PURCHASE': return 'text-blue-400';
      case 'EXPENSE': return 'text-rose-400';
      default: return 'text-slate-400';
    }
  };

  return (
    <div className="p-4 space-y-6 pb-24 bg-[#0f172a] min-h-screen">
      <header className="flex justify-between items-center">
        <div>
          <h1 className="text-2xl font-black text-white">Diary Scanner</h1>
          <p className="text-[10px] text-indigo-400 font-bold uppercase tracking-[0.2em]">Hisaab Automatic Karein</p>
        </div>
        <button 
          onClick={() => fileInputRef.current?.click()}
          className="w-12 h-12 rounded-2xl bg-indigo-500/10 border border-indigo-500/20 text-indigo-400 flex items-center justify-center active:scale-90 transition-all"
        >
          <i className="fas fa-camera text-xl"></i>
        </button>
      </header>

      <input 
        type="file" 
        accept="image/*" 
        capture="environment"
        className="hidden" 
        ref={fileInputRef} 
        onChange={handleImageUpload}
      />

      {!image && (
        <div 
          onClick={() => fileInputRef.current?.click()}
          className="border-2 border-dashed border-slate-700 bg-slate-800/20 rounded-[3rem] p-12 text-center space-y-6 cursor-pointer group hover:border-indigo-500/50 transition-all"
        >
          <div className="w-24 h-24 bg-indigo-500/10 rounded-full flex items-center justify-center mx-auto text-indigo-400 border border-indigo-500/20 group-hover:scale-110 transition-transform">
            <i className="fas fa-file-signature text-4xl"></i>
          </div>
          <div className="space-y-2">
            <p className="font-black text-white text-lg">Hath Se Likha Hisaab</p>
            <p className="text-xs text-slate-500 font-bold leading-relaxed px-4">
              Apni diary ya notebook ki photo khichein, Sudarshan automatic extract kar dega.
            </p>
          </div>
          <div className="pt-4">
            <span className="bg-indigo-600 text-white px-6 py-3 rounded-2xl text-xs font-black uppercase tracking-widest shadow-lg shadow-indigo-600/20">
              Photo Khichein
            </span>
          </div>
        </div>
      )}

      {image && !result && (
        <div className="space-y-6 animate-in fade-in duration-500">
          <div className="rounded-[2.5rem] overflow-hidden shadow-2xl border-4 border-slate-800 relative group">
            <img src={image} alt="Diary Preview" className="w-full h-auto object-cover grayscale-[20%]" />
            <div className="absolute inset-0 bg-gradient-to-t from-slate-950/80 via-transparent to-transparent flex items-end p-6">
              <p className="text-xs font-bold text-white/60">Ready to analyze...</p>
            </div>
          </div>
          <div className="grid grid-cols-2 gap-3">
             <button 
              onClick={() => setImage(null)}
              className="py-5 rounded-[1.5rem] glass-card text-slate-400 font-black text-[10px] uppercase tracking-widest"
             >
               Retake
             </button>
             <button 
              onClick={startAnalysis}
              disabled={loading}
              className="py-5 rounded-[1.5rem] bg-indigo-600 text-white font-black text-[10px] uppercase tracking-widest shadow-xl shadow-indigo-600/30 flex items-center justify-center gap-2"
            >
              {loading ? <i className="fas fa-spinner fa-spin"></i> : <i className="fas fa-wand-magic-sparkles"></i>}
              {loading ? 'Reading...' : 'Start Analysis'}
            </button>
          </div>
        </div>
      )}

      {result && (
        <div className="animate-in slide-in-from-bottom-8 duration-500 space-y-6">
          <div className="glass-card p-6 rounded-[2.5rem] border border-white/5 space-y-4">
            <div className="flex items-center gap-3 mb-2">
              <div className="w-10 h-10 rounded-2xl bg-emerald-500/10 flex items-center justify-center text-emerald-400">
                <i className="fas fa-check-double"></i>
              </div>
              <div>
                <h3 className="font-black text-white text-sm">Aaj Ka Hisaab</h3>
                <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">Analysis Done</p>
