const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const SYSTEM_INSTRUCTION = `
You are Sudarshan CRM Assistant, an AI expert for Indian MSMEs.
Your role: convert Hindi/Hinglish/English voice/text to structured JSON.
Localize all currencies to ₹. Use very simple Hindi for summaries.
Voice Personality: Reassuring, business-savvy, sounds like an experienced "Munim ji" but modern.
When answering questions about business growth, be specific to the Indian market.
`;

const DIARY_ANALYSIS_INSTRUCTION = `
Task: High-precision OCR and analysis of Indian business ledger (Diary).
Identify: Bikri (Sales), Kharid (Purchases), Kharcha (Expenses).
Output valid JSON only. Suggest 5 sharp business improvements in Hindi.
`;

export async function processChat(message: string): Promise<CrmAction> {
  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview", // Complex reasoning and Q&A
    contents: message,
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          action: { type: Type.STRING },
          parameters: { type: Type.OBJECT },
          reply: { type: Type.STRING }
        },
        required: ["action", "parameters", "reply"]
      }
    }
  });
  return JSON.parse(response.text || '{}') as CrmAction;
}

export async function speakHindi(text: string) {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: `Say in a helpful Indian male business assistant voice: ${text}` }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (base64Audio) {
      const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      const binary = atob(base64Audio);
      const bytes = new Uint8Array(binary.length);
      for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);

      const dataInt16 = new Int16Array(bytes.buffer);
      const buffer = audioCtx.createBuffer(1, dataInt16.length, 24000);
      const channelData = buffer.getChannelData(0);
      for (let i = 0; i < dataInt16.length; i++) channelData[i] = dataInt16[i] / 32768.0;

      const source = audioCtx.createBufferSource();
      source.buffer = buffer;
      source.connect(audioCtx.destination);
      source.start();
    }
  } catch (e) {
    console.error("TTS failed", e);
  }
}

export async function analyzeDiaryImage(base64Image: string): Promise<CrmAction> {
  const imagePart = { inlineData: { mimeType: 'image/jpeg', data: base64Image } };
  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: { parts: [imagePart, { text: "Read this Indian shop diary. Extract all entries and give 5 Hindi growth tips." }] },
    config: {
      systemInstruction: DIARY_ANALYSIS_INSTRUCTION,
      responseMimeType: "application/json"
    }
  });
  return JSON.parse(response.text || '{}') as CrmAction;
}

import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI, Modality, LiveServerMessage } from '@google/genai';

function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

function encode(bytes: Uint8Array) {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

const VoiceAssistant: React.FC = () => {
  const [isActive, setIsActive] = useState(false);
  const [status, setStatus] = useState('Tap to Start Live Help');
  const [transcription, setTranscription] = useState('');

  const audioContextRef = useRef<AudioContext | null>(null);
  const sessionRef = useRef<any>(null);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const nextStartTimeRef = useRef(0);

  const startSession = async () => {
    try {
      setStatus('Connecting...');
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

      const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      audioContextRef.current = audioCtx;

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        callbacks: {
          onopen: () => {
            setIsActive(true);
            setStatus('Munim Ji is Listening...');

            const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
            const source = inputCtx.createMediaStreamSource(stream);
            const scriptProcessor = inputCtx.createScriptProcessor(4096, 1, 1);

            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) {
                int16[i] = inputData[i] * 32768;
              }
              const pcmBlob = {
                data: encode(new Uint8Array(int16.buffer)),
                mimeType: 'audio/pcm;rate=16000',
              };
              sessionPromise.then(s => s.sendRealtimeInput({ media: pcmBlob }));
            };

            source.connect(scriptProcessor);
            scriptProcessor.connect(inputCtx.destination);
          },
          onmessage: async (msg: LiveServerMessage) => {
            if (msg.serverContent?.modelTurn?.parts[0]?.inlineData?.data) {
              const base64Audio = msg.serverContent.modelTurn.parts[0].inlineData.data;
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, audioCtx.currentTime);

              const audioBuffer = await decodeAudioData(decode(base64Audio), audioCtx, 24000, 1);
              const sourceNode = audioCtx.createBufferSource();
              sourceNode.buffer = audioBuffer;
              sourceNode.connect(audioCtx.destination);
              sourceNode.start(nextStartTimeRef.current);
              nextStartTimeRef.current += audioBuffer.duration;
              sourcesRef.current.add(sourceNode);
              sourceNode.onended = () => sourcesRef.current.delete(sourceNode);
            }

            if (msg.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => s.stop());
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
            }
          },
          onclose: () => {
            setIsActive(false);
            setStatus('Session Closed');
          },
          onerror: (err) => {
            console.error(err);
            setStatus('Connection Error');
          }
        },
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Puck' } } },
          systemInstruction: 'You are Munim Ji, a traditional but modern Indian business assistant. Talk naturally in Hinglish. Help the user manage their shop daily diary, sales, and khata.',
        }
      });

      sessionRef.current = await sessionPromise;
    } catch (err) {
      console.error(err);
      setStatus('Failed to Start');
    }
  };

  const stopSession = () => {
    if (sessionRef.current) {
      sessionRef.current.close();
    }
    setIsActive(false);
    setStatus('Tap to Start Live Help');
  };

  return (
    <div className="p-6 flex flex-col items-center justify-center min-h-[70vh] space-y-8">
      <div className="relative">
        <div className={`w-48 h-48 rounded-full flex items-center justify-center transition-all duration-700 ${isActive ? 'bg-orange-500/20 scale-110' : 'bg-slate-800'}`}>
          <div className={`w-32 h-32 rounded-full flex items-center justify-center transition-all duration-500 ${isActive ? 'bg-orange-500 shadow-[0_0_50px_rgba(249,115,22,0.5)] pulse' : 'bg-slate-700'}`}>
            <button 
              onClick={isActive ? stopSession : startSession}
              className="text-white text-5xl active:scale-90 transition-transform"
            >
              <i className={`fas ${isActive ? 'fa-stop' : 'fa-microphone'}`}></i>
            </button>
          </div>
          {isActive && (
            <div className="absolute inset-0 rounded-full border-4 border-orange-500/30 animate-ping"></div>
          )}
        </div>
      </div>

      <div className="text-center space-y-4">
        <h2 className="text-3xl font-black text-white tracking-tight">{status}</h2>
        <p className="text-slate-400 text-sm font-medium px-8 leading-relaxed italic">
          "Bhaiya, aaj ki bikri kitni hui?" - Munim Ji se Live baat karein.
        </p>
      </div>

      <div className="w-full max-w-xs space-y-3">
        <div className="glass-card p-4 rounded-3xl border border-white/5 flex items-center gap-4">
          <div className="w-10 h-10 rounded-full bg-green-500/10 flex items-center justify-center text-green-500">
            <i className="fab fa-whatsapp"></i>
          </div>
          <span className="text-xs font-bold text-white">WhatsApp Integration Live</span>
        </div>
        <div className="glass-card p-4 rounded-3xl border border-white/5 flex items-center gap-4">
          <div className="w-10 h-10 rounded-full bg-orange-500/10 flex items-center justify-center text-orange-500">
            <i className="fas fa-sparkles"></i>
          </div>
          <span className="text-xs font-bold text-white">Powered by Gemini AI</span>
        </div>
