const ChatAgent: React.FC = () => {
  const [messages, setMessages] = useState<{ text: string, sender: 'user' | 'bot' }[]>([
    { text: "Namaste! Main Sudarshan Assistant hoon. Business growth, billing ya kisi bhi sawaal ke liye puchhiye.", sender: 'bot' }
  ]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages, loading]);

  const handleSend = async () => {
    if (!input.trim() || loading) return;
    const userMsg = input;
    setMessages(prev => [...prev, { text: userMsg, sender: 'user' }]);
    setInput('');
    setLoading(true);

    try {
      const response: CrmAction = await processChat(userMsg);
      setMessages(prev => [...prev, { text: response.reply, sender: 'bot' }]);
      speakHindi(response.reply);
    } catch (error) {
      setMessages(prev => [...prev, { text: "Network thoda dheela hai, kripya dobara try karein.", sender: 'bot' }]);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-[calc(100vh-140px)] bg-[#020617]">
      <div ref={scrollRef} className="flex-1 overflow-y-auto p-5 space-y-6 scrollbar-hide">
        {messages.map((m, i) => (
          <div key={i} className={`flex ${m.sender === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[88%] p-5 rounded-[2rem] relative shadow-lg ${
              m.sender === 'user' 
                ? 'bg-gradient-to-r from-blue-600 to-indigo-700 text-white rounded-tr-none' 
                : 'glass-card text-white font-medium rounded-tl-none border border-slate-700/50'
            }`}>
              <p className="text-[15px] font-bold leading-relaxed">{m.text}</p>
              {m.sender === 'bot' && (
                <button 
                  onClick={() => speakHindi(m.text)}
