                >
                  <i className="fas fa-volume-up text-xs"></i>
                </button>
              )}
            </div>
          </div>
        ))}
        {loading && (
          <div className="flex justify-start">
            <div className="glass-card p-5 rounded-[2rem] rounded-tl-none flex gap-2 border border-slate-700/50">
              <span className="w-2 h-2 bg-orange-500 rounded-full animate-bounce"></span>
              <span className="w-2 h-2 bg-orange-500 rounded-full animate-bounce [animation-delay:0.2s]"></span>
              <span className="w-2 h-2 bg-orange-500 rounded-full animate-bounce [animation-delay:0.4s]"></span>
            </div>
          </div>
        )}
      </div>

      <div className="p-4 bg-slate-900/80 backdrop-blur-xl border-t border-slate-800">
        <div className="flex gap-2 max-w-md mx-auto items-center">
          <input 
            type="text" 
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder="Hindi ya English mein likhein..."
            className="flex-1 bg-slate-800 border border-slate-700 rounded-full px-6 py-4 text-[15px] font-bold text-white focus:outline-none focus:ring-4 focus:ring-blue-500/20 transition-all"
          />
          <button 
            onClick={handleSend}
            disabled={!input.trim()}
            className="bg-gradient-to-br from-orange-500 to-red-600 text-white w-14 h-14 rounded-full flex items-center justify-center shadow-xl shadow-orange-600/20 active:scale-90 transition-all disabled:opacity-30"
          >
            <i className="fas fa-paper-plane"></i>
          </button>
        </div>
        <p className="text-[9px] text-center text-slate-500 mt-4 font-black uppercase tracking-[0.3em]">AI Munim Ji at your service</p>
      </div>
    </div>
  );
};

