const BottomNav: React.FC<BottomNavProps> = ({ activeTab, setActiveTab }) => {
  const tabs = [
    { id: 'dashboard', icon: 'fa-chart-pie', label: 'Stats' },
    { id: 'customers', icon: 'fa-book-open', label: 'Khata' },
    { id: 'leads', icon: 'fa-layer-group', label: 'Kaam' },
