import { GoogleGenAI, Type, Modality } from "@google/genai";
import { CrmAction } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const SYSTEM_INSTRUCTION = `
You are Sudarshan CRM Assistant, an AI expert for Indian MSMEs.
Your role: convert Hindi/Hinglish/English voice/text to structured JSON.
Localize all currencies to ₹. Use very simple Hindi for summaries.
Voice Personality: Reassuring, business-savvy, sounds like an experienced "Munim ji" but modern.
`;

const DIARY_ANALYSIS_INSTRUCTION = `
Task: High-precision OCR and analysis of Indian business ledger (Diary).
Expertise: You are highly skilled in reading handwritten notes in Devanagari (Hindi, Marathi), Gujarati, Tamil, and Hinglish.
Context: Indian shopkeepers use abbreviations.
- "Bk." or "B" or "Sale" = Bikri (Sale)
- "Kh." or "E" or "Exp" = Kharcha (Expense)
- "Pur" or "Kr." = Kharid (Purchase)
- "Bal" = Balance
- "Cr/Dr" = Credit/Debit
- Symbols: "₹", "/-", "=".
Output valid JSON only. Identify transactions accurately even from messy handwriting.
Suggest 5 sharp business improvements in Hindi.
`;

export async function processChat(message: string): Promise<CrmAction> {
  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: message,
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          action: { type: Type.STRING },
          parameters: { type: Type.OBJECT },
          reply: { type: Type.STRING }
        },
        required: ["action", "parameters", "reply"]
      }
    }
  });
  return JSON.parse(response.text || '{}') as CrmAction;
}

export async function speakHindi(text: string) {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: `Say in a helpful Indian male business assistant voice: ${text}` }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (base64Audio) {
      const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      const binary = atob(base64Audio);
      const bytes = new Uint8Array(binary.length);
      for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);

      const dataInt16 = new Int16Array(bytes.buffer);
      const buffer = audioCtx.createBuffer(1, dataInt16.length, 24000);
      const channelData = buffer.getChannelData(0);
      for (let i = 0; i < dataInt16.length; i++) channelData[i] = dataInt16[i] / 32768.0;

      const source = audioCtx.createBufferSource();
      source.buffer = buffer;
      source.connect(audioCtx.destination);
      source.start();
    }
  } catch (e) {
    console.error("TTS failed", e);
  }
}

export async function transcribeAudio(base64Audio: string): Promise<string> {
  const audioPart = {
    inlineData: {
      mimeType: 'audio/webm', // Or audio/pcm;rate=16000
      data: base64Audio
    }
  };
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: { parts: [audioPart, { text: "Transcribe this audio strictly. If it is in Hindi or Hinglish, keep it that way." }] }
  });
  return response.text || '';
}

export async function analyzeDiaryImage(base64Image: string, transcriptionPrompt?: string): Promise<CrmAction> {
  const imagePart = { inlineData: { mimeType: 'image/jpeg', data: base64Image } };
  const textPrompt = transcriptionPrompt 
    ? `Read this shop diary accurately. Follow these specific instructions from the user: "${transcriptionPrompt}"`
    : "Read this shop diary accurately. Look for regional scripts and abbreviations.";

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: { parts: [imagePart, { text: textPrompt }] },
    config: {
      systemInstruction: DIARY_ANALYSIS_INSTRUCTION,
      responseMimeType: "application/json"
    }
  });
  return JSON.parse(response.text || '{}') as CrmAction;
}

import React, { useState, useRef } from 'react';
import { analyzeDiaryImage, speakHindi, transcribeAudio } from '../services/gemini';
import { CrmAction, Transaction } from '../types';

const DiaryAnalyzer: React.FC = () => {
  const [image, setImage] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [result, setResult] = useState<CrmAction | null>(null);
  const [transcription, setTranscription] = useState<string>('');
  const fileInputRef = useRef<HTMLInputElement>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setImage(reader.result as string);
        setResult(null);
        setTranscription('');
      };
      reader.readAsDataURL(file);
    }
  };

  const startAnalysis = async (customPrompt?: string) => {
    if (!image) return;
    setLoading(true);
    try {
      const base64Data = image.split(',')[1];
      const analysisResult = await analyzeDiaryImage(base64Data, customPrompt || transcription);
      setResult(analysisResult);
      if (analysisResult.insights?.summary_hindi) {
        speakHindi(analysisResult.insights.summary_hindi);
      }
    } catch (error) {
      alert("Analysis failed. Handwriting clearly scan karein.");
    } finally {
      setLoading(false);
    }
  };

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const recorder = new MediaRecorder(stream);
      mediaRecorderRef.current = recorder;
      audioChunksRef.current = [];

      recorder.ondataavailable = (e) => {
        if (e.data.size > 0) audioChunksRef.current.push(e.data);
      };

      recorder.onstop = async () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/webm' });
        const reader = new FileReader();
        reader.onloadend = async () => {
          const base64Audio = (reader.result as string).split(',')[1];
          setLoading(true);
          try {
            const text = await transcribeAudio(base64Audio);
            setTranscription(text);
            if (image) {
              await startAnalysis(text);
            } else {
              speakHindi("Prompt sunliya hai. Ab diary ki photo khichein.");
              fileInputRef.current?.click();
            }
          } catch (e) {
            console.error("Transcription failed", e);
          } finally {
            setLoading(false);
          }
        };
        reader.readAsDataURL(audioBlob);
        stream.getTracks().forEach(track => track.stop());
      };

      recorder.start();
      setIsRecording(true);
    } catch (err) {
      console.error("Could not start recording", err);
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
    }
  };

  return (
    <div className="p-5 space-y-6 pb-24 bg-white min-h-screen">
      <header className="flex justify-between items-center py-2">
        <div>
          <h1 className="text-2xl font-black text-slate-900">Diary Scanner</h1>
          <p className="text-[10px] text-orange-600 font-black uppercase tracking-[0.2em]">Hisaab Automatic Extract</p>
        </div>
        <div className="flex gap-2">
          <button 
            onClick={isRecording ? stopRecording : startRecording}
            className={`w-12 h-12 rounded-2xl flex items-center justify-center shadow-sm transition-all ${
              isRecording ? 'bg-rose-500 text-white animate-pulse' : 'bg-slate-100 text-slate-600 border border-slate-200'
            }`}
          >
            <i className={`fas ${isRecording ? 'fa-stop' : 'fa-microphone'} text-xl`}></i>
          </button>
          <button 
            onClick={() => fileInputRef.current?.click()}
            className="w-12 h-12 rounded-2xl bg-orange-50 text-orange-600 border border-orange-100 flex items-center justify-center shadow-sm"
          >
            <i className="fas fa-camera text-xl"></i>
          </button>
        </div>
      </header>

      <input 
        type="file" 
        accept="image/*" 
        capture="environment"
        className="hidden" 
        ref={fileInputRef} 
        onChange={handleImageUpload}
      />

      {transcription && (
        <div className="bg-indigo-50 p-4 rounded-2xl border border-indigo-100 flex items-center gap-3 animate-in slide-in-from-top-4">
          <i className="fas fa-quote-left text-indigo-300"></i>
          <p className="text-xs font-bold text-indigo-700 italic">"{transcription}"</p>
        </div>
      )}

      {!image && !loading && (
        <div 
          onClick={() => fileInputRef.current?.click()}
          className="border-2 border-dashed border-slate-200 bg-slate-50/50 rounded-[3rem] p-12 text-center space-y-6 cursor-pointer group hover:bg-slate-50 transition-all"
        >
          <div className="w-20 h-20 bg-white rounded-3xl flex items-center justify-center mx-auto text-orange-500 shadow-md group-hover:scale-105 transition-transform">
            <i className="fas fa-file-pen text-3xl"></i>
          </div>
          <div className="space-y-1">
            <p className="font-black text-slate-900 text-lg">Hath Se Likha Hisaab</p>
            <p className="text-xs text-slate-500 font-bold px-4">
              Photo khichein ya bolkar instruction dein (e.g. "Sirf total batayein").
            </p>
          </div>
          <button className="bg-slate-900 text-white px-8 py-3.5 rounded-2xl text-xs font-black uppercase tracking-widest shadow-xl">
            Photo Khichein
          </button>
        </div>
      )}

      {image && !result && !loading && (
        <div className="space-y-6 animate-in fade-in duration-500">
          <div className="rounded-[2.5rem] overflow-hidden shadow-xl border-4 border-white relative">
            <img src={image} alt="Diary Preview" className="w-full h-auto object-cover" />
          </div>
          <div className="flex gap-3">
             <button 
              onClick={() => {setImage(null); setTranscription('');}}
              className="flex-1 py-4 rounded-2xl bg-slate-100 text-slate-600 font-black text-[10px] uppercase tracking-widest"
             >
               Retake
             </button>
             <button 
              onClick={() => startAnalysis()}
              className="flex-[2] py-4 rounded-2xl bg-orange-500 text-white font-black text-[10px] uppercase tracking-widest shadow-lg shadow-orange-500/20"
            >
              <i className="fas fa-wand-magic-sparkles mr-2"></i>
              Analysis Start Karein
            </button>
          </div>
        </div>
      )}

      {loading && (
        <div className="flex flex-col items-center justify-center py-20 space-y-6">
          <div className="w-20 h-20 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
          <div className="text-center">
            <p className="font-black text-slate-900 text-lg uppercase tracking-tight">Processing...</p>
            <p className="text-xs text-slate-500 font-bold">Hisaab nikal rahe hain, kripya intezar karein.</p>
          </div>
        </div>
      )}

      {result && !loading && (
        <div className="space-y-6 animate-in slide-in-from-bottom-8">
           <div className="glass-card p-6 rounded-[2.5rem] space-y-4">
              <p className="text-sm font-bold text-slate-800 leading-relaxed bg-slate-50 p-4 rounded-2xl border-l-4 border-orange-500 italic">
                "{result.insights?.summary_hindi || result.reply}"
              </p>
              <div className="grid grid-cols-2 gap-3">
                 <div className="bg-emerald-50 p-4 rounded-2xl border border-emerald-100">
