                    <p className="text-[9px] font-black text-blue-600 uppercase mb-1">Hisaab Net</p>
                    <p className="text-xl font-black text-slate-900">₹{result.parameters?.profit_loss || '0'}</p>
                 </div>
              </div>
              {result.insights?.action_steps_hindi && (
                <div className="space-y-2 mt-4">
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Growth Steps</p>
                  {result.insights.action_steps_hindi.map((step, idx) => (
                    <div key={idx} className="flex gap-3 items-start bg-white p-3 rounded-xl border border-slate-100">
