import React, { useState, useRef } from 'react';
import { analyzeDiaryImage, speakHindi, transcribeAudio } from '../services/gemini';
import { CrmAction, Transaction } from '../types';

const DiaryAnalyzer: React.FC = () => {
  const [image, setImage] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [result, setResult] = useState<CrmAction | null>(null);
  const [transcription, setTranscription] = useState<string>('');
  const fileInputRef = useRef<HTMLInputElement>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setImage(reader.result as string);
        setResult(null);
        setTranscription('');
      };
      reader.readAsDataURL(file);
    }
  };

  const startAnalysis = async (customPrompt?: string) => {
    if (!image) return;
    setLoading(true);
    try {
      const base64Data = image.split(',')[1];
      const analysisResult = await analyzeDiaryImage(base64Data, customPrompt || transcription);
      setResult(analysisResult);
      if (analysisResult.insights?.summary_hindi) {
        speakHindi(analysisResult.insights.summary_hindi);
      }
    } catch (error) {
      alert("Analysis failed. Handwriting clearly scan karein.");
    } finally {
      setLoading(false);
    }
  };

  const handleGenerateReport = () => {
    if (!result) return;
    alert("Report teyar ho rahi hai...");
    const reportText = `
SUDARSHAN AI - DIARY ANALYSIS REPORT
------------------------------------
Date: ${new Date().toLocaleDateString('en-IN')}
User Request: ${transcription || 'Standard OCR Scan'}

SUMMARY (HINDI):
${result.insights?.summary_hindi || result.reply}

BUSINESS METRICS:
- Total Sale: ₹${result.parameters?.total_sale || '0'}
- Profit/Loss: ₹${result.parameters?.profit_loss || '0'}

ACTION STEPS:
${result.insights?.action_steps_hindi?.map((s, i) => `${i + 1}. ${s}`).join('\n') || 'No steps identified.'}

------------------------------------
Generated by Sudarshan AI Labs
    `;
    const blob = new Blob([reportText], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `Sudarshan_Diary_Report_${Date.now()}.txt`;
    link.click();
    URL.revokeObjectURL(url);
  };

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const recorder = new MediaRecorder(stream);
      mediaRecorderRef.current = recorder;
      audioChunksRef.current = [];

      recorder.ondataavailable = (e) => {
        if (e.data.size > 0) audioChunksRef.current.push(e.data);
      };

      recorder.onstop = async () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/webm' });
        const reader = new FileReader();
        reader.onloadend = async () => {
          const base64Audio = (reader.result as string).split(',')[1];
          setLoading(true);
          try {
            const text = await transcribeAudio(base64Audio);
            setTranscription(text);
            if (image) {
              await startAnalysis(text);
            } else {
              speakHindi("Instruction samajh liye hain. Ab dukan ki diary ki photo khichein.");
              fileInputRef.current?.click();
            }
          } catch (e) {
            console.error("Transcription failed", e);
          } finally {
            setLoading(false);
          }
        };
        reader.readAsDataURL(audioBlob);
        stream.getTracks().forEach(track => track.stop());
      };

      recorder.start();
      setIsRecording(true);
    } catch (err) {
      console.error("Mic access failed", err);
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
    }
  };

  return (
    <div className="p-6 space-y-10 pb-32 bg-white min-h-screen selection:bg-orange-100">
