          <h1 className="text-4xl font-black text-slate-900 tracking-tighter">Diary AI</h1>
          <p className="text-xs text-orange-600 font-black uppercase tracking-[0.2em]">Smart Khata Analyzer</p>
        </div>
        <div className="flex gap-4">
          <button 
            onClick={isRecording ? stopRecording : startRecording}
            className={`w-16 h-16 rounded-3xl flex items-center justify-center shadow-2xl transition-all ${
              isRecording ? 'bg-red-600 text-white animate-pulse' : 'bg-slate-900 text-white hover:bg-indigo-600'
            }`}
          >
            <i className={`fas ${isRecording ? 'fa-stop' : 'fa-microphone'} text-2xl`}></i>
          </button>
          <button 
            onClick={() => fileInputRef.current?.click()}
            className="w-16 h-16 rounded-3xl bg-indigo-600 text-white flex items-center justify-center shadow-xl shadow-indigo-100 active:scale-95 transition-transform"
          >
            <i className="fas fa-camera text-2xl"></i>
          </button>
        </div>
      </header>

      <input 
        type="file" 
        accept="image/*" 
        capture="environment"
        className="hidden" 
        ref={fileInputRef} 
        onChange={handleImageUpload}
      />

      {transcription && (
        <div className="bg-indigo-50 p-6 rounded-[2.5rem] border-2 border-indigo-100 flex items-center gap-5 animate-in slide-in-from-top-6 shadow-sm">
          <div className="w-12 h-12 bg-indigo-600 rounded-2xl flex items-center justify-center text-white shrink-0 shadow-lg">
            <i className="fas fa-quote-left text-lg"></i>
          </div>
          <p className="text-base font-black text-indigo-950 leading-tight italic">"{transcription}"</p>
        </div>
      )}

      {!image && !loading && (
        <div 
          onClick={() => fileInputRef.current?.click()}
          className="border-4 border-dashed border-slate-200 bg-slate-50/50 rounded-[4rem] p-16 text-center space-y-8 cursor-pointer group hover:bg-white hover:border-indigo-200 transition-all shadow-inner"
        >
          <div className="w-32 h-32 bg-white rounded-[2rem] flex items-center justify-center mx-auto text-indigo-600 shadow-2xl group-hover:scale-105 transition-transform border border-slate-100">
            <i className="fas fa-file-signature text-6xl"></i>
