            <p className="text-lg text-slate-600 font-bold leading-relaxed px-6">
              Mic button dabayein or instructions dein, fir photo khichein.
            </p>
          </div>
          <button className="bg-indigo-600 text-white px-12 py-5 rounded-2xl text-sm font-black uppercase tracking-widest shadow-2xl flex items-center justify-center gap-3 mx-auto active:scale-95">
